head.b:skin:
/* Minimum CSS required by Blogger */
body {
  margin: 0;
  padding: 0;
}

body.script:
// Theme Switcher Engine for Blogger
function applyBloggerTheme(isLight) {
  const body = document.body;
  const iconSun = document.getElementById("theme-icon-sun");
  const iconMoon = document.getElementById("theme-icon-moon");

  if (isLight) {
    body.classList.add("light-mode");
    if (iconSun) iconSun.classList.remove("hidden");
    if (iconMoon) iconMoon.classList.add("hidden");
  } else {
    body.classList.remove("light-mode");
    if (iconSun) iconSun.classList.add("hidden");
    if (iconMoon) iconMoon.classList.remove("hidden");
  }
}

function toggleBloggerTheme() {
  const isLight = !document.body.classList.contains("light-mode");
  applyBloggerTheme(isLight);
  localStorage.setItem("blogger_theme_mode", isLight ? "light" : "dark");
}

// Load theme on startup
const savedTheme = localStorage.getItem("blogger_theme_mode");
const prefersLight = savedTheme === "light";
applyBloggerTheme(prefersLight);

setTimeout(() => {
  const splash = document.getElementById("hub-portal-splash");
  if (splash) {
    splash.style.opacity = "0";
    splash.style.transform = "translateY(-20px)";
    splash.style.pointerEvents = "none";
    setTimeout(() => splash.remove(), 700);
  }
}, 2500);

  //
    // Configured modules list injected dynamically
    let MODULES = [
  {
    "id": "admin",
    "name": "siModArO - Admin & Developer Hub",
    "description": "Pusat konfigurasi, Kalender Pendidikan, pendaftaran GuruID, dan generator blueprint modular.",
    "url": "https://ais-dev-k3l3nfmwij7hyxqj3knrf5-502754005172.asia-east1.run.app",
    "icon": "ShieldAlert"
  },
  {
    "id": "identitas",
    "name": "siModArO - Identitas Guru",
    "description": "Pengisian biodata guru, data sekolah SMAN 1 Amonggedo, & koneksi ke Google Drive.",
    "url": "https://simodaro-identitas.vercel.app/",
    "icon": "Award",
    "underDevelopment": false
  },
  {
    "id": "analisis-cp",
    "name": "siModArO - Analisis CP",
    "description": "Analisis Capaian Pembelajaran (CP) ke Tujuan Pembelajaran (TP) & penentuan Alur (ATP).",
    "url": "https://simodaro-analisis-cp.blogspot.com",
    "icon": "BookOpen",
    "underDevelopment": true
  },
  {
    "id": "alokasi-waktu",
    "name": "siModArO - Analisis Alokasi Waktu",
    "description": "Perhitungan rincian minggu efektif, kegiatan tidak efektif, dan distribusi jam pelajaran (JP).",
    "url": "https://simodaro-alokasi-waktu.blogspot.com",
    "icon": "Calendar",
    "underDevelopment": true
  },
  {
    "id": "kktp",
    "name": "siModArO - KKTP",
    "description": "Penyusunan Kriteria Ketercapaian Tujuan Pembelajaran dengan SOLO Taxonomy.",
    "url": "https://simodaro-kktp.blogspot.com",
    "icon": "Award",
    "underDevelopment": true
  },
  {
    "id": "modul-ajar",
    "name": "siModArO - Modul Ajar",
    "description": "Pembuatan RPP/Modul Ajar interaktif berbasis Deep Learning & kecerdasan AI Gemini.",
    "url": "https://simodaro-modul-ajar.blogspot.com",
    "icon": "Sparkles",
    "underDevelopment": true
  },
  {
    "id": "custom-i3x6sfi",
    "name": "LittlePdf V1.3",
    "description": "Aplikasi untuk Mengecilkan ukuran Pdf",
    "url": "",
    "icon": "Layers",
    "underDevelopment": true
  }
];
    const savedModules = localStorage.getItem("hub_modules");
    if (savedModules) {
      try {
        MODULES = JSON.parse(savedModules);
      } catch (e) {
        console.error("Gagal membaca hub_modules", e);
      }
    }

    // Initialize Firebase in Blogger layout
    let db;
    try {
      firebase.initializeApp({"projectId":"simodaro-web","appId":"1:723460308896:web:4f5ff2dd382e84c0336ec5","apiKey":"AIzaSyA6EhknIaMSR4yOaT2R2T5_qds5NYmukSk","authDomain":"simodaro-web.firebaseapp.com","storageBucket":"simodaro-web.firebasestorage.app","messagingSenderId":"723460308896","measurementId":""});
      db = firebase.firestore();
    } catch (e) {
      console.warn("Koneksi Firebase Cloud Offline, menggunakan local fallback.");
    }

    // Load State from local storage
    document.getElementById("hub-guruid").value = localStorage.getItem("hub_guruid") || "";
    document.getElementById("hub-nama").value = localStorage.getItem("hub_nama") || "";
    document.getElementById("hub-gemini").value = localStorage.getItem("hub_gemini") || "";

    // Load active module or default to first non-admin
    let activeModuleId = localStorage.getItem("hub_active_module");
    if (!activeModuleId || activeModuleId === "admin") {
      const firstNonAdmin = MODULES.find(m => m.id !== 'admin');
      activeModuleId = firstNonAdmin ? firstNonAdmin.id : MODULES[0].id;
    }

    // Render Top Navigation Modules (as compact buttons with tooltip on info icon)
    function renderModules() {
      const topNavContainer = document.getElementById("top-modules-container");
      if (!topNavContainer) return;
      topNavContainer.innerHTML = "";

      MODULES.forEach(mod => {
        // Exclude Admin & Developer Hub from regular modular list
        if (mod.id === "admin") return;

        // Create a wrapper group button element
        const btn = document.createElement("div");
        btn.id = "btn-" + mod.id;
        btn.className = "group relative flex items-center bg-slate-900 border border-slate-800 hover:border-slate-700 rounded-xl px-3 py-1.5 transition duration-150 cursor-pointer select-none text-xs gap-2 pr-7";

        // Select module on click of the main button area (not the info icon)
        btn.onclick = (e) => {
          const target = e.target;
          if (target && target.classList && target.classList.contains('info-trigger')) {
            return; // Skip if they clicked the 'i' icon specifically
          }
          selectModule(mod.id);
        };

        // Clean prefix "siModArO - " from button text
        const cleanName = mod.name.replace(/^siModArO\s*-\s*/i, '');
        const titleSpan = document.createElement("span");
        titleSpan.className = "font-extrabold text-slate-300 block tracking-wide module-title whitespace-nowrap";
        titleSpan.innerText = cleanName;
        btn.appendChild(titleSpan);

        const isDev = mod.underDevelopment || !mod.url || mod.url.trim() === "" || mod.url.trim() === "#" || mod.url.trim().toLowerCase() === "belum ada" || mod.url.trim().toLowerCase() === "belum diset";
        if (isDev) {
          const devDot = document.createElement("span");
          devDot.className = "w-1.5 h-1.5 rounded-full bg-amber-500 shrink-0";
          devDot.title = "Dalam Pengembangan";
          btn.appendChild(devDot);
        } else {
          const activeDot = document.createElement("span");
          activeDot.className = "w-1.5 h-1.5 rounded-full bg-emerald-500 shrink-0 animate-pulse";
          activeDot.title = "Aktif";
          btn.appendChild(activeDot);
        }

        // Information icon 'i' on top-right of the button
        const infoSpan = document.createElement("span");
        infoSpan.className = "info-trigger absolute top-1 right-1.5 w-3.5 h-3.5 rounded-full bg-slate-800 border border-slate-700 text-[8px] font-bold font-mono text-slate-400 hover:text-white hover:bg-slate-700 flex items-center justify-center cursor-help transition-colors duration-150";
        infoSpan.innerText = "i";
        btn.appendChild(infoSpan);

        // Interactive Tooltip popover showing name, status, and description
        const tooltip = document.createElement("div");
        tooltip.className = "absolute top-full left-1/2 -translate-x-1/2 mt-2 w-64 p-3.5 bg-slate-900 border border-slate-700 text-slate-100 rounded-xl shadow-2xl opacity-0 scale-95 pointer-events-none transition-all duration-150 z-50 group-hover:opacity-100 group-hover:scale-100 group-focus-within:opacity-100 group-focus-within:scale-100 leading-relaxed text-justify";

        const tooltipHeader = document.createElement("div");
        tooltipHeader.className = "font-extrabold text-xxs text-emerald-400 uppercase tracking-widest border-b border-slate-800 pb-1 mb-2 flex items-center justify-between gap-1";

        const tooltipTitle = document.createElement("span");
        tooltipTitle.className = "truncate max-w-[150px]";
        tooltipTitle.innerText = mod.name;
        tooltipHeader.appendChild(tooltipTitle);

        const tooltipBadge = document.createElement("span");
        tooltipBadge.className = "shrink-0 text-[7px] font-extrabold px-1 py-0.5 rounded uppercase tracking-wider bg-slate-950 border " + (isDev ? "text-amber-500 border-amber-500/20" : "text-emerald-500 border-emerald-500/20");
        tooltipBadge.innerText = isDev ? "🛠️ Dev" : "🟢 Aktif";
        tooltipHeader.appendChild(tooltipBadge);
        tooltip.appendChild(tooltipHeader);

        const tooltipDesc = document.createElement("p");
        tooltipDesc.className = "text-[10px] text-slate-300 font-sans font-medium normal-case leading-normal";
        tooltipDesc.innerText = mod.description;
        tooltip.appendChild(tooltipDesc);

        btn.appendChild(tooltip);
        topNavContainer.appendChild(btn);
      });

      // Highlight current active
      selectModule(activeModuleId);
    }

    // Try fetching live modules from Firestore Cloud to avoid re-pasting the XML code
    if (db) {
      db.collection("school_settings").doc("modular_theme").get()
        .then(docSnap => {
          if (docSnap.exists) {
            const cloudData = docSnap.data();
            if (cloudData.title) {
              document.title = cloudData.title;
              const titleNode = document.getElementById("blog-header-title");
              if (titleNode) titleNode.innerText = cloudData.title;
            }
            if (cloudData.accent) {
              document.documentElement.style.setProperty('--theme-accent', cloudData.accent);
              const indicator = document.getElementById("active-mod-indicator");
              if (indicator) indicator.style.backgroundColor = cloudData.accent;
            }
            if (cloudData.saranUrl !== undefined) {
              localStorage.setItem("hub_saran_url", cloudData.saranUrl);
            }
            if (cloudData.modules && cloudData.modules.length > 0) {
              MODULES = cloudData.modules;
              localStorage.setItem("hub_modules", JSON.stringify(MODULES));
              renderModules();
            }
          }
        })
        .catch(err => {
          console.warn("Gagal sinkron dari cloud, menggunakan local fallback:", err);
        });
    }

    // Toggle Sidebar collapsible state
    function toggleSidebar() {
      const sidebar = document.getElementById("sidebar-panel");
      if (sidebar) {
        sidebar.classList.toggle("sidebar-collapsed");
      }
    }

    // Dynamic Filter Modules via Top Search Input
    function filterModules() {
      const searchInput = document.getElementById("module-search-top");
      if (!searchInput) return;
      const query = searchInput.value.toLowerCase().trim();
      MODULES.forEach(mod => {
        if (mod.id === "admin") return;
        const btn = document.getElementById("btn-" + mod.id);
        if (btn) {
          const matches = mod.name.toLowerCase().includes(query) || mod.description.toLowerCase().includes(query);
          if (matches) {
            btn.style.display = "flex";
          } else {
            btn.style.display = "none";
          }
        }
      });
    }

    function selectModule(id) {
      if (id === "admin") {
        const adminMod = MODULES.find(m => m.id === "admin");
        const adminUrl = adminMod ? adminMod.url : window.location.origin;
        const guruId = encodeURIComponent(localStorage.getItem("hub_guruid") || "");
        const nama = encodeURIComponent(localStorage.getItem("hub_nama") || "");
        const gemini = encodeURIComponent(localStorage.getItem("hub_gemini") || "");
        const divider = adminUrl.includes("?") ? "\x26" : "?";
        const fullUrl = `${adminUrl}${divider}guruId=${guruId}\x26nama=${nama}\x26gemini=${gemini}`;
        window.open(fullUrl, '_blank');
        return;
      }

      const mod = MODULES.find(m => m.id === id) || MODULES[0];
      activeModuleId = mod.id;
      localStorage.setItem("hub_active_module", id);

      // Highlight active button (only for non-admin items, admin relies on the gear)
      MODULES.forEach(m => {
        const el = document.getElementById("btn-" + m.id);
        if (el) {
          if (m.id === id) {
            el.className = "group relative flex items-center bg-slate-850 rounded-xl px-3 py-1.5 transition duration-150 cursor-pointer select-none text-xs gap-2 pr-7 shadow-lg border-2";
            el.style.borderColor = "var(--theme-accent)";
            const titleEl = el.querySelector(".module-title");
            if (titleEl) titleEl.style.color = "var(--theme-accent)";
          } else {
            el.className = "group relative flex items-center bg-slate-900 border border-slate-800 hover:border-slate-700 rounded-xl px-3 py-1.5 transition duration-150 cursor-pointer select-none text-xs gap-2 pr-7 text-slate-400";
            el.style.borderColor = "";
            const titleEl = el.querySelector(".module-title");
            if (titleEl) titleEl.style.color = "#e2e8f0";
          }
        }
      });

      // Update Top Indicator
      document.getElementById("active-mod-title").innerText = mod.name.toUpperCase();

      const iframe = document.getElementById("main-hub-iframe");
      const devOverlay = document.getElementById("dev-overlay");
      const isUnderDev = mod.underDevelopment || !mod.url || mod.url.trim() === "" || mod.url.trim() === "#" || mod.url.trim().toLowerCase() === "belum ada" || mod.url.trim().toLowerCase() === "belum diset";

      if (isUnderDev) {
        if (iframe) iframe.style.display = "none";
        if (devOverlay) devOverlay.classList.remove("hidden");
      } else {
        if (iframe) iframe.style.display = "block";
        if (devOverlay) devOverlay.classList.add("hidden");

        // Load iframe with parameters so the children apps automatically receive configurations via URL
        const guruId = encodeURIComponent(localStorage.getItem("hub_guruid") || "");
        const nama = encodeURIComponent(localStorage.getItem("hub_nama") || "");
        const gemini = encodeURIComponent(localStorage.getItem("hub_gemini") || "");

        const divider = mod.url.includes("?") ? "\x26" : "?";
        const fullUrl = `${mod.url}${divider}guruId=${guruId}\x26nama=${nama}\x26gemini=${gemini}\x26embedded=true`;

        if (iframe) iframe.src = fullUrl;
      }
    }

    function syncGlobalState() {
      const gId = document.getElementById("hub-guruid").value.trim();
      const nama = document.getElementById("hub-nama").value.trim();
      const gemini = document.getElementById("hub-gemini").value.trim();

      localStorage.setItem("hub_guruid", gId);
      localStorage.setItem("hub_nama", nama);
      localStorage.setItem("hub_gemini", gemini);

      // Instantly propagate state to active iframe via postMessage
      const iframe = document.getElementById("main-hub-iframe");
      if (iframe && iframe.contentWindow) {
        iframe.contentWindow.postMessage({
          type: "SIMODARO_SYNC_STATE",
          guruId: gId,
          namaGuru: nama,
          geminiApiKey: gemini
        }, "*");
      }
    }

    function saveIdentitasDenganTombol() {
      syncGlobalState();

      // Remove any existing notification
      const existing = document.getElementById("save-notif-toast");
      if (existing) existing.remove();

      // Show a green visual notification inside the page
      const alertBox = document.createElement("div");
      alertBox.id = "save-notif-toast";
      alertBox.className = "fixed bottom-4 right-4 z-50 bg-emerald-500 text-slate-950 px-4 py-3 rounded-xl font-bold font-sans text-xs flex items-center gap-2 shadow-2xl transition-all duration-300 transform translate-y-0 opacity-100";
      alertBox.style.boxShadow = "0 20px 25px -5px rgba(16, 185, 129, 0.2), 0 10px 10px -5px rgba(16, 185, 129, 0.1)";
      alertBox.innerHTML = `
        <svg class="w-4 h-4 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24" style="stroke-width: 2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M5 13l4 4L19 7"/></svg>
        <span>Identitas Guru & API Key Berhasil Disimpan Ke Browser!</span>
      `;
      document.body.appendChild(alertBox);

      setTimeout(() => {
        alertBox.style.opacity = "0";
        alertBox.style.transform = "translateY(10px)";
        setTimeout(() => alertBox.remove(), 400);
      }, 3500);
    }

    function reloadActiveIframe() {
      selectModule(activeModuleId);
    }

    function openCurrentInNewTab() {
      const mod = MODULES.find(m => m.id === activeModuleId);
      if (mod && mod.url && mod.url !== "#" && mod.url.trim().toLowerCase() !== "belum ada" && mod.url.trim().toLowerCase() !== "belum diset") {
        const rawGuruId = localStorage.getItem("hub_guruid") || "";
        if (!rawGuruId) {
          alert("Silakan isi dan simpan Identitas Guru (Guru ID) terlebih dahulu sebelum membuka modul di tab baru.");
          return;
        }
        const guruId = encodeURIComponent(rawGuruId);
        const nama = encodeURIComponent(localStorage.getItem("hub_nama") || "");
        const gemini = encodeURIComponent(localStorage.getItem("hub_gemini") || "");

        const divider = mod.url.includes("?") ? "\x26" : "?";
        const fullUrl = `${mod.url}${divider}guruId=${guruId}\x26nama=${nama}\x26gemini=${gemini}`;
        window.open(fullUrl, '_blank');
      } else {
        alert("Modul belum tersedia atau sedang dalam perbaikan.");
      }
    }

    async function submitSaran() {
      const nama = document.getElementById("hub-nama").value.trim();
      const guruId = document.getElementById("hub-guruid").value.trim();
      const modular = document.getElementById("saran-modular").value;
      const saran = document.getElementById("saran-text").value.trim();

      if (!nama) {
        alert("Silakan isi NAMA LENGKAP PENDIDIK terlebih dahulu di bagian Identitas Guru.");
        return;
      }
      if (!saran) {
        alert("Silakan tulis isi saran atau masukan Anda.");
        return;
      }

      const btn = document.getElementById("btn-kirim-saran");
      if (btn) {
        btn.disabled = true;
        btn.innerText = "⏳ MENGIRIM SARAN...";
      }

      const payload = {
        namaGuru: nama,
        guruId: guruId || "Tanpa ID",
        modular: modular || "Umum",
        saran: saran,
        timestamp: new Date().toISOString()
      };

      try {
        const sheetUrl = "https://script.google.com/macros/s/AKfycbyiGpLIAAc3Id6DuRFPHn-2XGatUb3IDdIFwPWB-zRhDJLrnzoSYx0Ic8-qb_IZdhV-Qg/exec" || localStorage.getItem("hub_saran_url") || "";

        let sheetSuccess = false;
        if (sheetUrl && sheetUrl.startsWith("http")) {
          try {
            const formBody = new URLSearchParams();
            formBody.append("namaGuru", payload.namaGuru);
            formBody.append("guruId", payload.guruId);
            formBody.append("modular", payload.modular);
            formBody.append("saran", payload.saran);

            await fetch(sheetUrl, {
              method: "POST",
              mode: "no-cors",
              headers: {
                "Content-Type": "application/x-www-form-urlencoded"
              },
              body: formBody.toString()
            });
            sheetSuccess = true;
          } catch (e) {
            console.warn("Gagal mengirim ke sheet", e);
          }
        }

        let dbSuccess = false;
        if (db) {
          try {
            const timeoutPromise = new Promise((_, reject) => 
              setTimeout(() => reject(new Error("Timeout: Jaringan lambat atau offline. Pastikan rules Firestore mengizinkan write.")), 8000)
            );

            await Promise.race([
              db.collection("saran_komentar").add(payload),
              timeoutPromise
            ]);
            dbSuccess = true;
          } catch (e) {
            console.warn("Gagal mengirim ke Firestore", e);
          }
        } 

        if (sheetSuccess || dbSuccess) {
          alert("🎉 Terima kasih! Saran/Komentar Anda berhasil terkirim ke pusat data SMAN 1 Amonggedo.");
          document.getElementById("saran-text").value = "";
        } else {
          // Offline fallback
          const offline = JSON.parse(localStorage.getItem("offline_saran") || "[]");
          offline.push(payload);
          localStorage.setItem("offline_saran", JSON.stringify(offline));
          alert("👍 Koneksi cloud sibuk. Saran disimpan sementara secara lokal & akan disinkronkan saat terhubung kembali!");
          document.getElementById("saran-text").value = "";
        }
      } catch (err) {
        console.error("Gagal mengirim saran:", err);
        // Fallback local
        const offline = JSON.parse(localStorage.getItem("offline_saran") || "[]");
        offline.push(payload);
        localStorage.setItem("offline_saran", JSON.stringify(offline));
        alert("👍 Saran disimpan secara offline karena keterbatasan jaringan. Terima kasih!");
        document.getElementById("saran-text").value = "";
      } finally {
        if (btn) {
          btn.disabled = false;
          btn.innerText = "🚀 KIRIM SARAN KE PUSAT";
        }
      }
    }

    // Initial load
    renderModules();

    // Watch for postMessage feedback from modular apps
    window.addEventListener("message", (event) => {
      if (event.data && event.data.type === "SIMODARO_UPDATE_STATE") {
        if (event.data.guruId) {
          document.getElementById("hub-guruid").value = event.data.guruId;
          localStorage.setItem("hub_guruid", event.data.guruId);
        }
        if (event.data.namaGuru) {
          document.getElementById("hub-nama").value = event.data.namaGuru;
          localStorage.setItem("hub_nama", event.data.namaGuru);
        }
        syncGlobalState();
      } else if (event.data && event.data.type === "SIMODARO_SYNC_MODULES") {
        if (event.data.modules) {
          localStorage.setItem("hub_modules", JSON.stringify(event.data.modules));
          window.location.reload();
        }
      }
    });
  //
